import{_ as a,o as r,c as e,ae as l}from"./chunks/framework.DD8idMxO.js";const g=JSON.parse('{"title":"Trace2Skill","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-trace2skill.md","filePath":"radar/tech-trace2skill.md"}'),o={name:"radar/tech-trace2skill.md"};function i(n,t,s,h,d,u){return r(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="trace2skill" tabindex="-1">Trace2Skill <a class="header-anchor" href="#trace2skill" aria-label="Permalink to &quot;Trace2Skill&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 生成 | <strong>成熟度</strong>: 🟢 成熟期 | <strong>综合评分</strong>: 0.61</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: <strong>并行多 sub-agent 编队</strong>从轨迹池蒸馏 Skill —— 整体归纳，避免逐条轨迹过拟合。35B 模型 +57.65pp 超越 122B。</p><p><strong>来源</strong>:</p><ul><li>阿里 Qwen 团队 + ETH Zurich</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2603.25158" target="_blank" rel="noreferrer">arXiv 2603.25158</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="并行多-agent-分析" tabindex="-1">并行多 Agent 分析 <a class="header-anchor" href="#并行多-agent-分析" aria-label="Permalink to &quot;并行多 Agent 分析&quot;">​</a></h3><p>不是一条条轨迹顺序处理，而是<strong>同时派出一支 sub-agent 编队</strong>并行分析整个轨迹池，分两组：</p><ul><li><strong>成功分析师</strong> —— &quot;这些做对的案例有什么共同点？&quot;</li><li><strong>错误分析师</strong> —— &quot;这些做错的案例卡在哪？&quot;</li></ul><p>每组独立提出 Skill 补丁建议。</p><h3 id="层级合并-程序化冲突检测" tabindex="-1">层级合并 + 程序化冲突检测 <a class="header-anchor" href="#层级合并-程序化冲突检测" aria-label="Permalink to &quot;层级合并 + 程序化冲突检测&quot;">​</a></h3><p>所有补丁不是简单拼接，而是通过<strong>层级归纳推理</strong>合并为一个无冲突的 Skill 目录。</p><p><strong>例</strong>：分析师 A 建议&quot;遇到 timeout 时重试 3 次&quot;，分析师 B 建议&quot;切换备用 API&quot; → 合并器识别冲突，选择支持证据更多的方案，或组合为&quot;先重试 3 次，仍失败则切换&quot;。</p><h3 id="关键数字" tabindex="-1">关键数字 <a class="header-anchor" href="#关键数字" aria-label="Permalink to &quot;关键数字&quot;">​</a></h3><ul><li><strong>35B 模型 + Trace2Skill Skill 在 WikiTableQuestions 上超越 122B agent +57.65pp</strong> —— 小模型 + 好 Skill 可打败大模型</li></ul><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="主要能力" tabindex="-1">主要能力 <a class="header-anchor" href="#主要能力" aria-label="Permalink to &quot;主要能力&quot;">​</a></h3><ul><li>并行轨迹分析，规模化</li><li>程序化冲突检测 + 格式验证</li><li>跨模型迁移有效</li></ul><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>需要<strong>大量并行执行轨迹</strong>作为输入，冷启动场景受限</li><li>合并阶段在&quot;信号部分相关或存在领域偏差&quot;时的行为尚不清楚</li><li>蒸馏出的 Skill 可解释性较差 —— &quot;人很难读懂 LLM 写给自己的 Skill&quot;</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.65</td><td>论文 + 阿里 Qwen 实证</td></tr><tr><td>创新性</td><td>0.80</td><td>并行编队 + 层级合并是新颖路径</td></tr><tr><td>落地程度</td><td>0.45</td><td>实证有效但工具未开源</td></tr><tr><td>生态活跃度</td><td>0.50</td><td>Qwen 生态背书</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.61</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2603.25158" target="_blank" rel="noreferrer">Trace2Skill 论文</a></li></ul>',33)])])}const q=a(o,[["render",i]]);export{g as __pageData,q as default};
